const students = [
    { id: 1, name: "Lukas Huber",    alter: 28, groesse: 182, geburtsdatum: "1997-05-12", herkunft: "Österreich",  gewicht: 78.5, note: 1 },
    { id: 2, name: "Sarah Meyer",    alter: 34, groesse: 165, geburtsdatum: "1991-11-20", herkunft: "Deutschland", gewicht: 62.0, note: 5 },
    { id: 3, name: "Mateo Rossi",    alter: 19, groesse: 175, geburtsdatum: "2006-02-28", herkunft: "Italien",     gewicht: 70.2, note: 4 },
    { id: 4, name: "Elena Fischer",  alter: 45, groesse: 170, geburtsdatum: "1980-08-05", herkunft: "Schweiz",     gewicht: 65.8, note: 2 },
    { id: 5, name: "Julian Novak",   alter: 22, groesse: 190, geburtsdatum: "2003-12-15", herkunft: "Österreich",  gewicht: 85.3, note: 3 },
    { id: 6, name: "Sophie Dubois",  alter: 31, groesse: 168, geburtsdatum: "1994-03-10", herkunft: "Frankreich",  gewicht: 59.5, note: 1 },
    { id: 7, name: "Erik Lindström", alter: 52, groesse: 185, geburtsdatum: "1973-10-22", herkunft: "Schweden",    gewicht: 92.1, note: 5 },
];

const solutions = {
    1: "const passed = students.filter(s => s.note <= 4);",
    2: "const labels = students.map(s => `${s.name} (${s.alter})`);",
    3: "const passedNames = students\n    .filter(s => s.note <= 4)\n    .map(s => s.name);",
    4: "const averageGrade = students.reduce((sum, s) => sum + s.note, 0) / students.length;",
    5: "const result = students\n    .filter(s => s.alter >= 17)\n    .filter(s => s.note <= 4)\n    .map(s => s.name)\n    .join(', ');"
};

const taskMeta = {
    1: { title: "Task 1 – filter",         desc: "Finde alle Studierenden, die bestanden haben (note <= 4). Speichere das Ergebnis in passed." },
    2: { title: "Task 2 – map",            desc: 'Erstelle ein Array von Strings im Format "Lukas Huber (28)". Speichere es in labels.' },
    3: { title: "Task 3 – filter + map",   desc: "Extrahiere aus den bestandenen Studierenden (note <= 4) nur deren Namen in ein Array passedNames." },
    4: { title: "Task 4 – reduce",         desc: "Berechne die Durchschnittsnote aller Studierenden. Speichere das Ergebnis in averageGrade." },
    5: { title: "Task 5 – Chaining Bonus", desc: "In einer einzigen Kette: Finde die Namen aller Studierenden mit alter >= 17 die bestanden haben (note <= 4), verbunden als kommaseparierten String. Speichere in result." },
};

const validators = {
    1(code) {
        const fn = new Function('students', code + '; return passed;');
        const res = fn(students);
        if (!Array.isArray(res)) return { ok: false, msg: "Fehler: passed muss ein Array sein." };
        const exp = students.filter(s => s.note <= 4);
        const ok = JSON.stringify(res) === JSON.stringify(exp);
        return {
            ok,
            msg: ok
                ? `Richtig! passed = [${res.map(s => s.name).join(', ')}]`
                : `Falsch: ${res.length} Einträge erhalten, ${exp.length} erwartet. Prüfe deine Bedingung.`
        };
    },
    2(code) {
        const fn = new Function('students', code + '; return labels;');
        const res = fn(students);
        if (!Array.isArray(res)) return { ok: false, msg: "Fehler: labels muss ein Array sein." };
        const exp = students.map(s => `${s.name} (${s.alter})`);
        const ok = JSON.stringify(res) === JSON.stringify(exp);
        return {
            ok,
            msg: ok
                ? `Richtig! labels = ["${res[0]}", "${res[1]}", ...]`
                : `Falsch: Erster Wert: "${res[0]}", erwartet: "${exp[0]}"`
        };
    },
    3(code) {
        const fn = new Function('students', code + '; return passedNames;');
        const res = fn(students);
        if (!Array.isArray(res)) return { ok: false, msg: "Fehler: passedNames muss ein Array sein." };
        const exp = students.filter(s => s.note <= 4).map(s => s.name);
        const ok = JSON.stringify(res) === JSON.stringify(exp);
        return {
            ok,
            msg: ok
                ? `Richtig! passedNames = [${res.map(n => `"${n}"`).join(', ')}]`
                : `Falsch: [${res.join(', ')}] erhalten, [${exp.join(', ')}] erwartet`
        };
    },
    4(code) {
        const fn = new Function('students', code + '; return averageGrade;');
        const res = fn(students);
        const exp = students.reduce((s, x) => s + x.note, 0) / students.length;
        const ok = Math.abs(res - exp) < 0.001;
        return {
            ok,
            msg: ok
                ? `Richtig! averageGrade = ${res}`
                : `Falsch: ${res} erhalten, ${exp} erwartet`
        };
    },
    5(code) {
        const fn = new Function('students', code + '; return result;');
        const res = fn(students);
        const exp = students
            .filter(s => s.alter >= 17)
            .filter(s => s.note <= 4)
            .map(s => s.name)
            .join(', ');
        const ok = res === exp;
        return {
            ok,
            msg: ok
                ? `Richtig! result = "${res}"`
                : `Falsch:\nErhalten:  "${res}"\nErwartet: "${exp}"`
        };
    }
};

let solved = new Set();

// Gespeicherte Lösungen aus den Textareas (beim Abschließen)
const userSolutions = {};

function updateProgress() {
    const pct = (solved.size / 5) * 100;
    document.getElementById('progressFill').style.width = pct + '%';
    document.getElementById('progressLabel').textContent = `Fortschritt: ${solved.size} / 5`;

    const btn    = document.getElementById('btn-export');
    const hint   = document.getElementById('export-hint');
    const allDone = solved.size === 5;

    btn.disabled = !allDone;
    hint.style.display = allDone ? 'none' : 'inline';
}

function runTask(id) {
    const code = document.getElementById(`code-${id}`).value.trim();
    const box  = document.getElementById(`result-${id}`);

    if (!code) {
        box.className = 'output-box info';
        box.textContent = 'Schreibe deinen Code oben in das Feld und klicke dann auf Ausführen.';
        return;
    }

    try {
        const { ok, msg } = validators[id](code);
        box.className = `output-box ${ok ? 'pass' : 'fail'}`;
        box.textContent = msg;
        if (ok) {
            solved.add(id);
            userSolutions[id] = code;
        }
    } catch (e) {
        box.className = 'output-box fail';
        box.textContent = `Fehler: ${e.message}`;
    }

    updateProgress();
}

function toggleHint(id) {
    document.getElementById(`hint-${id}`).classList.toggle('show');
}

function showSolution(id) {
    document.getElementById(`code-${id}`).value = solutions[id];
    const box = document.getElementById(`result-${id}`);
    box.className = 'output-box info';
    box.textContent = 'Lösung angezeigt – klicke auf Ausführen zum Überprüfen.';
}

function scrollToTop() {
    document.getElementById('top').scrollIntoView({ behavior: 'smooth' });
}

// ── Export-Logik ──────────────────────────────────────────

function toggleExport() {
    const panel = document.getElementById('export-panel');
    const isHidden = panel.style.display === 'none';
    panel.style.display = isHidden ? 'block' : 'none';
    if (isHidden) renderExport();
}

function getUsedCode(id) {
    // Prefer what the user typed (if they solved it themselves), else the solution
    return userSolutions[id] || solutions[id];
}

function buildJSON() {
    const data = {
        datensatz: students,
        tasks: {}
    };

    for (let i = 1; i <= 5; i++) {
        const key = `task${i}`;
        data.tasks[key] = {
            titel:   taskMeta[i].title,
            aufgabe: taskMeta[i].desc,
            loesung: getUsedCode(i)
        };
    }

    return JSON.stringify(data, null, 2);
}

function escapeXML(str) {
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&apos;');
}

function buildXML() {
    let xml = '<?xml version="1.0" encoding="UTF-8"?>\n';
    xml += '<arrow_functions_loesung>\n\n';

    xml += '  <datensatz>\n';
    students.forEach(s => {
        xml += '    <student>\n';
        xml += `      <id>${s.id}</id>\n`;
        xml += `      <name>${escapeXML(s.name)}</name>\n`;
        xml += `      <alter>${s.alter}</alter>\n`;
        xml += `      <groesse>${s.groesse}</groesse>\n`;
        xml += `      <geburtsdatum>${s.geburtsdatum}</geburtsdatum>\n`;
        xml += `      <herkunft>${escapeXML(s.herkunft)}</herkunft>\n`;
        xml += `      <gewicht>${s.gewicht}</gewicht>\n`;
        xml += `      <note>${s.note}</note>\n`;
        xml += '    </student>\n';
    });
    xml += '  </datensatz>\n\n';

    xml += '  <tasks>\n';
    for (let i = 1; i <= 5; i++) {
        xml += `    <task id="${i}">\n`;
        xml += `      <titel>${escapeXML(taskMeta[i].title)}</titel>\n`;
        xml += `      <aufgabe>${escapeXML(taskMeta[i].desc)}</aufgabe>\n`;
        xml += `      <loesung>${escapeXML(getUsedCode(i))}</loesung>\n`;
        xml += '    </task>\n';
    }
    xml += '  </tasks>\n\n';
    xml += '</arrow_functions_loesung>';

    return xml;
}

function renderExport() {
    const format = document.getElementById('format-select').value;
    const output = document.getElementById('export-output');
    output.value = format === 'xml' ? buildXML() : buildJSON();
}

function downloadExport() {
    const format   = document.getElementById('format-select').value;
    const content  = document.getElementById('export-output').value;
    const mimeType = format === 'xml' ? 'application/xml' : 'application/json';
    const filename = `arrow_functions_LOESUNG.${format}`;

    const blob = new Blob([content], { type: mimeType });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement('a');
    a.href     = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
}

// ── Tab-Unterstützung in Textareas ────────────────────────
document.querySelectorAll('textarea:not(.export-output)').forEach(ta => {
    ta.addEventListener('keydown', e => {
        if (e.key === 'Tab') {
            e.preventDefault();
            const s = ta.selectionStart;
            ta.value = ta.value.slice(0, s) + '  ' + ta.value.slice(ta.selectionEnd);
            ta.selectionStart = ta.selectionEnd = s + 2;
        }
        if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
            const id = parseInt(ta.id.split('-')[1]);
            if (!isNaN(id)) runTask(id);
        }
    });
});

updateProgress();


/* ── Injected ── */
function toggleSwitcher(btn) {
    btn.classList.toggle('open');
    document.getElementById('switcherMenu').classList.toggle('open');
}
document.addEventListener('click', function(e) {
    if (!e.target.closest('.switcher-inner')) {
        document.querySelectorAll('.switcher-btn').forEach(b => b.classList.remove('open'));
        document.querySelectorAll('.switcher-menu').forEach(m => m.classList.remove('open'));
    }
});
function initSwitcher(currentId, label, iconSrc) {
    const icon = document.getElementById('switcherIcon');
    const lbl = document.getElementById('switcherLabel');
    if (icon) { icon.src = iconSrc; icon.alt = label; }
    if (lbl) lbl.textContent = label;
    document.querySelectorAll('.switcher-item').forEach(item => {
        if (item.dataset.id === currentId) item.classList.add('active');
    });
}

initSwitcher('js','Arrow Functions – HÜ','data:image/png;base64,');

